good-example.code-block:
package com.example.orders.architecture;

import com.tngtech.archunit.core.importer.ImportOption;
import com.tngtech.archunit.junit.AnalyzeClasses;
import com.tngtech.archunit.junit.ArchTest;
import com.tngtech.archunit.lang.ArchRule;

import static com.tngtech.archunit.library.Architectures.onionArchitecture;

@AnalyzeClasses(
        packages = "com.example.orders",
        importOptions = ImportOption.DoNotIncludeTests.class)
class OnionArchitectureTest {

    @ArchTest
    static final ArchRule onion_boundaries = onionArchitecture()
            .domainModels("com.example.orders.domain.model..")
            .domainServices("com.example.orders.domain.service..")
            .applicationServices("com.example.orders.application..")
            .adapter("rest", "com.example.orders.adapter.rest..")
            .adapter("persistence", "com.example.orders.adapter.persistence..")
            .adapter("messaging", "com.example.orders.adapter.messaging..");
}

